 builder.Services.AddScoped<IUserService, UserService>();

 // BREAKING CHANGE #1 (ValidateOnBuild/ValidateScopes enabled in dev):
 // A singleton was capturing a scoped IUserService — this now throws at
 // startup in development.  Fix: register CacheService as scoped too.
 builder.Services.AddScoped<ICacheService>(sp =>
     new CacheService(sp.GetRequiredService<IUserService>()));

 // BREAKING CHANGE #2 (HttpClientFactory default handler is SocketsHttpHandler):
 // The cast to HttpClientHandler now throws InvalidCastException.
 // Fix: use ConfigurePrimaryHttpMessageHandler with an explicit handler.
 builder.Services.AddHttpClient("api")
     .ConfigurePrimaryHttpMessageHandler(() =>
         new SocketsHttpHandler { UseCookies = false });

 // BREAKING CHANGE #3 (Trace-level header logging now redacted by default):
 // Fix: allowlist the specific non-sensitive headers you need for debugging.
 builder.Services.ConfigureHttpClientDefaults(b =>
     b.RedactLoggedHeaders(header =>
         header != "X-Request-Id"
         && header != "X-Correlation-Id"
         && header != "Content-Type"
         && header != "Accept"
         && header != "Cache-Control"
         && header != "X-Forwarded-For"
         && header != "X-Forwarded-Proto"));

 // BREAKING CHANGE #4 (ForwardedHeaders middleware ignores unknown proxies):
 // Fix: add your trusted proxy addresses to KnownProxies/KnownNetworks.
 builder.Services.Configure<ForwardedHeadersOptions>(options =>
 {
     options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
     // TODO: add your actual reverse-proxy addresses here, e.g.:
     // options.KnownProxies.Add(System.Net.IPAddress.Parse("10.0.0.1"));
 });
 var app = builder.Build();
 app.UseForwardedHeaders();
 app.Run();

 // Stub types for compilation
 public interface IUserService { }
 public class UserService : IUserService { }
 public interface ICacheService { }
 public class CacheService : ICacheService
 {
     public CacheService(IUserService userService) { }
 }
